import{stripVTControlCharacters}from"node:util";const CONTROL_CHARACTERS=/\u001b\[[0-9;]+m/g;export const ELLIPSIS="…";const getTruncatedParts=(t,r,e)=>{const n=[];let o=0,s=0,a=!1;for(;s<t.length;){CONTROL_CHARACTERS.lastIndex=s;const c=CONTROL_CHARACTERS.exec(t);c&&c.index===s?(s=CONTROL_CHARACTERS.lastIndex,n.push(c[0])):(e&&o>=r?a=!0:n.push(t[s]),o++,s++)}if(e)return{parts:n,truncated:a};let c=0;return{parts:n.reverse().filter(t=>t.length>1||c++<r).reverse(),truncated:c>r}};export const truncate=(t,r)=>{if(stripVTControlCharacters(t).length<=r)return t;const{parts:e,truncated:n}=getTruncatedParts(t,r-ELLIPSIS.length,!0);return n?1===e.at(-1)?.length?e.join("")+ELLIPSIS:[...e.slice(0,-1),ELLIPSIS,e.at(-1)].join(""):t};export const truncateStart=(t,r)=>{if(stripVTControlCharacters(t).length<=r)return t;const{parts:e,truncated:n}=getTruncatedParts(t,r-ELLIPSIS.length,!1);return n?1===e[0].length?ELLIPSIS+e.join(""):[e[0],ELLIPSIS,...e.slice(1)].join(""):t};export const pad=(t,r,e,n)=>{const o=r+(t.length-stripVTControlCharacters(t).length);return"right"===n?t.padStart(o,e):"center"===n?t.padStart((t.length+o)/2,e).padEnd(o,e):t.padEnd(o,e)};export const prettyMilliseconds=t=>{const r=t/1e3,e=Math.floor(r/60),n=Math.floor(e/60);return n>0?`${n}h ${e%60}m ${Math.floor(r%60)}s`:e>0?`${e}m ${Math.floor(r%60)}s`:r>10?`${Math.round(r)}s`:r>1?`${r.toFixed(1)}s`:`${Math.round(t)}ms`};